#ifndef DEFAULT_ORDER
#define DEFAULT_ORDER 256
#endif

typedef struct record {
    int value;
} record;

typedef struct knode {
    int location;
    int indices[DEFAULT_ORDER + 1];
    int keys[DEFAULT_ORDER + 1];
    int is_leaf;
    int num_keys;
} knode;

__kernel void
findK(long maxheight,
      __global knode *knodes,
      long knodes_elem,
      __global record *records,
      __global long *currKnode,
      __global long *offset,
      __global int *keys,
      __global record *ans)
{
    long bid = (long)get_group_id(0);
    int thid = (int)get_local_id(0);
    long i;

    for (i = 0; i < maxheight; i++) {
        long curr = currKnode[bid];
        long off = offset[bid];
        int key = keys[bid];

        if ((knodes[curr].keys[thid] <= key) &&
            (knodes[curr].keys[thid + 1] > key)) {
            if ((long)knodes[off].indices[thid] < knodes_elem) {
                offset[bid] = (long)knodes[off].indices[thid];
            }
        }

        barrier(CLK_GLOBAL_MEM_FENCE);

        if (thid == 0) {
            currKnode[bid] = offset[bid];
        }

        barrier(CLK_GLOBAL_MEM_FENCE);
    }

    if (keys[bid] == knodes[currKnode[bid]].keys[thid]) {
        ans[bid].value = records[knodes[currKnode[bid]].indices[thid]].value;
    }
}

