__kernel void
findRangeK(long maxheight,
           __global knode *knodes,
           long knodes_elem,
           __global long *currKnode,
           __global long *offset,
           __global long *lastKnode,
           __global long *offset_2,
           __global int *start,
           __global int *end,
           __global int *recstart,
           __global int *reclength)
{
    long bid = (long)get_group_id(0);
    int thid = (int)get_local_id(0);
    long i;

    for (i = 0; i < maxheight; i++) {
        long curr = currKnode[bid];
        long last = lastKnode[bid];
        int s = start[bid];
        int e = end[bid];

        if ((knodes[curr].keys[thid] <= s) &&
            (s < knodes[curr].keys[thid + 1])) {
            if (knodes_elem > (long)knodes[curr].indices[thid]) {
                offset[bid] = (long)knodes[curr].indices[thid];
            }
        }

        if ((e >= knodes[last].keys[thid]) &&
            (e < knodes[last].keys[thid + 1])) {
            if (knodes_elem > (long)knodes[last].indices[thid]) {
                offset_2[bid] = (long)knodes[last].indices[thid];
            }
        }

        barrier(CLK_GLOBAL_MEM_FENCE);

        if (thid == 0) {
            currKnode[bid] = offset[bid];
            lastKnode[bid] = offset_2[bid];
        }

        barrier(CLK_GLOBAL_MEM_FENCE);
    }

    if (knodes[currKnode[bid]].keys[thid] == start[bid]) {
        recstart[bid] = knodes[currKnode[bid]].indices[thid];
    }

    barrier(CLK_GLOBAL_MEM_FENCE);

    if (knodes[lastKnode[bid]].keys[thid] == end[bid]) {
        reclength[bid] = knodes[lastKnode[bid]].indices[thid] - recstart[bid] + 1;
    }
}
